<span class="line"><span style="color:#171717;font-weight:bold">    for</span><span style="color:#6E6961">(</span><span style="color:#171717;font-weight:bold">int</span><span style="color:#171717"> i</span><span style="color:#171717;font-weight:bold">=</span><span style="color:#3D3A35">0</span><span style="color:#6E6961">;</span><span style="color:#171717">i</span><span style="color:#171717;font-weight:bold">&#x3C;</span><span style="color:#171717">n</span><span style="color:#6E6961">;</span><span style="color:#171717">i</span><span style="color:#171717;font-weight:bold">++</span><span style="color:#6E6961">)</span></span>
