<span class="line"><span style="color:#171717;font-weight:bold">    int</span><span style="color:#171717"> curL</span><span style="color:#171717;font-weight:bold">=</span><span style="color:#171717">l</span><span style="color:#6E6961">,</span><span style="color:#171717">curR</span><span style="color:#171717;font-weight:bold">=</span><span style="color:#171717">m</span><span style="color:#171717;font-weight:bold">+</span><span style="color:#3D3A35">1</span><span style="color:#6E6961">;</span><span style="color:#76716A;font-style:italic"> //左右分为[l,m] [m+1,r]</span></span>
